package com.example.myapp;

import com.getcapacitor.JSObject;
import com.getcapacitor.Plugin;
import com.getcapacitor.PluginCall;
import com.getcapacitor.PluginMethod;
import com.getcapacitor.annotation.CapacitorPlugin;

@CapacitorPlugin(name = "Counter")
public class CounterPlugin extends Plugin {

    private int counter = 0;

    @PluginMethod
    public void increment(PluginCall call) {
        counter++;
        JSObject data = new JSObject();
        data.put("value", counter);
        notifyListeners("change", data);
        call.resolve(data);
    }

    @PluginMethod
    public void reset(PluginCall call) {
        counter = 0;
        JSObject data = new JSObject();
        data.put("value", 0);
        notifyListeners("change", data);
        call.resolve(data);
    }

    @PluginMethod
    public void getValue(PluginCall call) {
        JSObject data = new JSObject();
        data.put("value", counter);
        call.resolve(data);
    }
}

package com.example.myapp;

import android.os.Bundle;
import com.getcapacitor.BridgeActivity;

public class MainActivity extends BridgeActivity {
    @Override
    public void onCreate(Bundle savedInstanceState) {
        registerPlugin(CounterPlugin.class);
        super.onCreate(savedInstanceState);
    }
}

import { registerPlugin, PluginListenerHandle } from '@capacitor/core';

export interface CounterPlugin {
  increment(): Promise<{ value: number }>;
  reset(): Promise<{ value: number }>;
  getValue(): Promise<{ value: number }>;
  addListener(eventName: 'change', listenerFunc: (data: { value: number }) => void): Promise<PluginListenerHandle>;
}

const Counter = registerPlugin<CounterPlugin>('Counter');

export default Counter;

import Counter from './counter';

async function main(): Promise<void> {
  const handle = await Counter.addListener('change', (data: { value: number }) => {
    console.log('Counter changed:', data.value);
  });

  await Counter.increment();
  await Counter.increment();
  await Counter.reset();
  const result = await Counter.getValue();
  console.log('Current value:', result.value);

  await handle.remove();
}

main();

